package com.enterprise.auth.service;

import com.enterprise.auth.entity.BackupCode;
import com.enterprise.auth.entity.User;
import com.enterprise.auth.repository.BackupCodeRepository;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.security.SecureRandom;
import java.time.Instant;
import java.time.temporal.ChronoUnit;
import java.util.ArrayList;
import java.util.List;

@Service
public class BackupCodeService {

    private static final Logger logger = LoggerFactory.getLogger(BackupCodeService.class);

    private static final int BACKUP_CODE_COUNT = 10;
    private static final int CODE_SEGMENT_LENGTH = 4;
    private static final int CODE_SEGMENTS = 2;
    private static final String CODE_CHARACTERS = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789"; // Excludes ambiguous chars I,O,0,1

    private final BackupCodeRepository backupCodeRepository;
    private final PasswordEncoder passwordEncoder;
    private final SecureRandom secureRandom;

    @Value("${mfa.backup-code.expiry-days:365}")
    private int backupCodeExpiryDays;

    public BackupCodeService(BackupCodeRepository backupCodeRepository, PasswordEncoder passwordEncoder) {
        this.backupCodeRepository = backupCodeRepository;
        this.passwordEncoder = passwordEncoder;
        this.secureRandom = new SecureRandom();
    }

    @Transactional
    public List<String> generateBackupCodes(User user) {
        // Revoke all existing backup codes
        backupCodeRepository.deleteAllByUser(user);

        List<String> plainTextCodes = new ArrayList<>();
        Instant expiresAt = Instant.now().plus(backupCodeExpiryDays, ChronoUnit.DAYS);

        for (int i = 0; i < BACKUP_CODE_COUNT; i++) {
            String code = generateSecureCode();
            plainTextCodes.add(code);

            // Hash the backup code before storing - never store plaintext
            String hashedCode = passwordEncoder.encode(normalizeCode(code));

            BackupCode backupCode = new BackupCode(user, hashedCode, expiresAt);
            backupCodeRepository.save(backupCode);
        }

        logger.info("Generated {} backup codes for user: {}", BACKUP_CODE_COUNT, user.getUsername());
        return plainTextCodes;
    }

    @Transactional
    public boolean validateAndConsumeBackupCode(User user, String providedCode, String ipAddress) {
        String normalizedCode = normalizeCode(providedCode);

        List<BackupCode> validCodes = backupCodeRepository.findValidCodesByUser(user);

        for (BackupCode backupCode : validCodes) {
            // Use constant-time comparison via BCrypt's built-in check
            if (passwordEncoder.matches(normalizedCode, backupCode.getCodeHash())) {
                // Mark the code as used
                backupCode.setUsed(true);
                backupCode.setUsedAt(Instant.now());
                backupCode.setUsedFromIp(ipAddress);
                backupCodeRepository.save(backupCode);

                long remaining = backupCodeRepository.countValidCodesByUser(user);
                logger.info("Backup code consumed for user: {}. Remaining codes: {}", user.getUsername(), remaining);

                if (remaining <= 2) {
                    logger.warn("User {} has only {} backup codes remaining!", user.getUsername(), remaining);
                }

                return true;
            }
        }

        logger.warn("Invalid backup code attempt for user: {} from IP: {}", user.getUsername(), ipAddress);
        return false;
    }

    public long getRemainingCodesCount(User user) {
        return backupCodeRepository.countValidCodesByUser(user);
    }

    @Transactional
    public void revokeAllBackupCodes(User user) {
        backupCodeRepository.deleteAllByUser(user);
        logger.info("All backup codes revoked for user: {}", user.getUsername());
    }

    @Transactional
    public int cleanupExpiredCodes() {
        int deleted = backupCodeRepository.deleteExpiredCodes();
        if (deleted > 0) {
            logger.info("Cleaned up {} expired backup codes", deleted);
        }
        return deleted;
    }

    private String generateSecureCode() {
        StringBuilder code = new StringBuilder();
        for (int segment = 0; segment < CODE_SEGMENTS; segment++) {
            if (segment > 0) {
                code.append('-');
            }
            for (int i = 0; i < CODE_SEGMENT_LENGTH; i++) {
                int index = secureRandom.nextInt(CODE_CHARACTERS.length());
                code.append(CODE_CHARACTERS.charAt(index));
            }
        }
        return code.toString();
    }

    private String normalizeCode(String code) {
        if (code == null) {
            return "";
        }
        // Remove dashes and whitespace, convert to uppercase for consistent comparison
        return code.replaceAll("[\\s-]", "").toUpperCase().trim();
    }
}

