package com.enterprise.auth.service;

import com.enterprise.auth.entity.AuditLog;
import com.enterprise.auth.entity.User;
import com.enterprise.auth.repository.AuditLogRepository;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.scheduling.annotation.Async;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.Instant;
import java.time.temporal.ChronoUnit;
import java.util.List;

@Service
public class AuditService {

    private static final Logger logger = LoggerFactory.getLogger(AuditService.class);

    private final AuditLogRepository auditLogRepository;

    public AuditService(AuditLogRepository auditLogRepository) {
        this.auditLogRepository = auditLogRepository;
    }

    @Async
    @Transactional
    public void logEvent(User user, String action, String details, String ipAddress, String userAgent, boolean success) {
        try {
            AuditLog log = new AuditLog(user, action, details, ipAddress, userAgent, success);
            auditLogRepository.save(log);
        } catch (Exception e) {
            logger.error("Failed to write audit log for action: {} user: {}", action,
                    user != null ? user.getUsername() : "unknown", e);
        }
    }

    public long countRecentFailedAttempts(User user, String action, int minutes) {
        Instant since = Instant.now().minus(minutes, ChronoUnit.MINUTES);
        List<AuditLog> attempts = auditLogRepository.findRecentFailedAttempts(user, action, since);
        return attempts.size();
    }

    public long countRecentFailedAttemptsByIp(String ipAddress, String action, int minutes) {
        Instant since = Instant.now().minus(minutes, ChronoUnit.MINUTES);
        return auditLogRepository.countRecentFailedAttemptsByIp(ipAddress, action, since);
    }
}

// ==================== Service: RateLimitService ====================

package com.enterprise.auth.service;

import com.enterprise.auth.exception.RateLimitExceededException;
import org.springframework.stereotype.Service;

import java.time.Instant;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicInteger;

@Service
public class RateLimitService {

    private static final int MAX_ATTEMPTS_PER_IP = 20;
    private static final int MAX_ATTEMPTS_PER_USER = 10;
    private static final int WINDOW_SECONDS = 900; // 15 minutes

    private final Map<String, RateLimitEntry> ipLimits = new ConcurrentHashMap<>();
    private final Map<String, RateLimitEntry> userLimits = new ConcurrentHashMap<>();

    public void checkRateLimit(String ipAddress, String username) {
        checkIpRateLimit(ipAddress);
        if (username != null) {
            checkUserRateLimit(username);
        }
    }

    public void recordAttempt(String ipAddress, String username) {
        recordIpAttempt(ipAddress);
        if (username != null) {
            recordUserAttempt(username);
        }
    }

    private void checkIpRateLimit(String ipAddress) {
        RateLimitEntry entry = ipLimits.get(ipAddress);
        if (entry != null && !entry.isExpired() && entry.getCount() >= MAX_ATTEMPTS_PER_IP) {
            throw new RateLimitExceededException("Too many requests from IP: " + ipAddress);
        }
    }

    private void checkUserRateLimit(String username) {
        RateLimitEntry entry = userLimits.get(username);
        if (entry != null && !entry.isExpired() && entry.getCount() >= MAX_ATTEMPTS_PER_USER) {
            throw new RateLimitExceededException("Too many requests for user: " + username);
        }
    }

    private void recordIpAttempt(String ipAddress) {
        ipLimits.compute(ipAddress, (key, entry) -> {
            if (entry == null || entry.isExpired()) {
                return new RateLimitEntry();
            }
            entry.increment();
            return entry;
        });
    }

    private void recordUserAttempt(String username) {
        userLimits.compute(username, (key, entry) -> {
            if (entry == null || entry.isExpired()) {
                return new RateLimitEntry();
            }
            entry.increment();
            return entry;
        });
    }

    private static class RateLimitEntry {
        private final Instant windowStart;
        private final AtomicInteger count;

        RateLimitEntry() {
            this.windowStart = Instant.now();
            this.count = new AtomicInteger(1);
        }

        boolean isExpired() {
            return Instant.now().isAfter(windowStart.plusSeconds(WINDOW_SECONDS));
        }

        int getCount() {
            return count.get();
        }

        void increment() {
            count.incrementAndGet();
        }
    }
}

// ==================== Service: TotpService ====================

package com.enterprise.auth.service;

import org.springframework.stereotype.Service;

import javax.crypto.Mac;
import javax.crypto.spec.SecretKeySpec;
import java.nio.ByteBuffer;
import java.security.InvalidKeyException;
import java.security.NoSuchAlgorithmException;
import java.security.SecureRandom;
import java.time.Instant;
import java.util.Base64;

@Service
public class TotpService {

    private static final int SECRET_LENGTH = 20;
    private static final int CODE_DIGITS = 6;
    private static final int TIME_STEP_SECONDS = 30;
    private static final int ALLOWED_TIME_DRIFT = 1; // Allow 1 step before/after
    private static final String HMAC_ALGORITHM = "HmacSHA1";

    private final SecureRandom secureRandom = new SecureRandom();

    public String generateSecret() {
        byte[] secretBytes = new byte[SECRET_LENGTH];
        secureRandom.nextBytes(secretBytes);
        return Base32Encoder.encode(secretBytes);
    }

    public boolean verifyCode(String secret, String code) {
        if (secret == null || code == null || code.length() != CODE_DIGITS) {
            return false;
        }

        try {
            int providedCode = Integer.parseInt(code);
            long currentTimeStep = Instant.now().getEpochSecond() / TIME_STEP_SECONDS;

            byte[] secretBytes = Base32Encoder.decode(secret);

            // Check current time step and allowed drift
            for (int i = -ALLOWED_TIME_DRIFT; i <= ALLOWED_TIME_DRIFT; i++) {
                int expectedCode = generateTotpCode(secretBytes, currentTimeStep + i);
                // Constant-time comparison
                if (constantTimeEquals(providedCode, expectedCode)) {
                    return true;
                }
            }
        } catch (NumberFormatException e) {
            return false;
        }

        return false;
    }

    public String generateQrCodeUri(String secret, String username, String issuer) {
        return String.format("otpauth://totp/%s:%s?secret=%s&issuer=%s&algorithm=SHA1&digits=%d&period=%d",
                issuer, username, secret, issuer, CODE_DIGITS, TIME_STEP_SECONDS);
    }

    private int generateTotpCode(byte[] secret, long timeStep) {
        byte[] timeBytes = ByteBuffer.allocate(8).putLong(timeStep).array();

        try {
            Mac mac = Mac.getInstance(HMAC_ALGORITHM);
            mac.init(new SecretKeySpec(secret, HMAC_ALGORITHM));
            byte[] hash = mac.doFinal(timeBytes);

            int offset = hash[hash.length - 1] & 0x0F;
            int truncatedHash = ((hash[offset] & 0x7F) << 24)
                    | ((hash[offset + 1] & 0xFF) << 16)
                    | ((hash[offset + 2] & 0xFF) << 8)
                    | (hash[offset + 3] & 0xFF);

            return truncatedHash % (int) Math.pow(10, CODE_DIGITS);
        } catch (NoSuchAlgorithmException | InvalidKeyException e) {
            throw new RuntimeException("Failed to generate TOTP code", e);
        }
    }

    private boolean constantTimeEquals(int a, int b) {
        return (a ^ b) == 0;
    }

    // Simple Base32 encoder/decoder
    private static class Base32Encoder {
        private static final String BASE32_CHARS = "ABCDEFGHIJKLMNOPQRSTUVWXYZ234567";

        static String encode(byte[] data) {
            StringBuilder result = new StringBuilder();
            int buffer = 0;
            int bitsLeft = 0;

            for (byte b : data) {
                buffer = (buffer << 8) | (b & 0xFF);
                bitsLeft += 8;
                while (bitsLeft >= 5) {
                    result.append(BASE32_CHARS.charAt((buffer >> (bitsLeft - 5)) & 0x1F));
                    bitsLeft -= 5;
                }
            }

            if (bitsLeft > 0) {
                result.append(BASE32_CHARS.charAt((buffer << (5 - bitsLeft)) & 0x1F));
            }

            return result.toString();
        }

        static byte[] decode(String encoded) {
            encoded = encoded.toUpperCase().replaceAll("[^A-Z2-7]", "");
            byte[] result = new byte[encoded.length() * 5 / 8];
            int buffer = 0;
            int bitsLeft = 0;
            int index = 0;

            for (char c : encoded.toCharArray()) {
                int val = BASE32_CHARS.indexOf(c);
                if (val < 0) continue;
                buffer = (buffer << 5) | val;
                bitsLeft += 5;
                if (bitsLeft >= 8) {
                    result[index++] = (byte) (buffer >> (bitsLeft - 8));
                    bitsLeft -= 8;
                }
            }

            return result;
        }
    }
}

// ==================== Service: AuthenticationService ====================

package com.enterprise.auth.service;

import com.enterprise.auth.dto.*;
import com.enterprise.auth.entity.User;
import com.enterprise.auth.exception.AccountLockedException;
import com.enterprise.auth.exception.AuthenticationException;
import com.enterprise.auth.exception.MfaException;
import com.enterprise.auth.repository.UserRepository;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.Instant;
import java.time.temporal.ChronoUnit;
import java.util.List;

@Service
public class AuthenticationService {

    private static final Logger logger = LoggerFactory.getLogger(AuthenticationService.class);

    private static final int MAX_FAILED_ATTEMPTS = 5;
    private static final int LOCKOUT_DURATION_MINUTES = 30;
    private static final String ISSUER = "EnterpriseAuth";

    private final UserRepository userRepository;
    private final PasswordEncoder passwordEncoder;
    private final TotpService totpService;
    private final BackupCodeService backupCodeService;
    private final AuditService auditService;
    private final RateLimitService rateLimitService;

    public AuthenticationService(UserRepository userRepository,
                                  PasswordEncoder passwordEncoder,
                                  TotpService totpService,
                                  BackupCodeService backupCodeService,
                                  AuditService auditService,
                                  RateLimitService rateLimitService) {
        this.userRepository = userRepository;
        this.passwordEncoder = passwordEncoder;
        this.totpService = totpService;
        this.backupCodeService = backupCodeService;
        this.auditService = auditService;
        this.rateLimitService = rateLimitService;
    }

    @Transactional
    public ApiResponse register(RegisterRequest request) {
        if (userRepository.existsByUsername(request.getUsername())) {
            return new ApiResponse(false, "Username already exists");
        }

        if (userRepository.existsByEmail(request.getEmail())) {
            return new ApiResponse(false, "Email already registered");
        }

        User user = new User(
                request.getUsername(),
                passwordEncoder.encode(request.getPassword()),
                request.getEmail()
        );

        userRepository.save(user);
        logger.info("New user registered: {}", request.getUsername());

        return new ApiResponse(true, "User registered successfully");
    }

    @Transactional
    public ApiResponse login(LoginRequest request, String ipAddress, String userAgent) {
        rateLimitService.checkRateLimit(ipAddress, request.getUsername());

        User user = userRepository.findByUsername(request.getUsername())
                .orElse(null);

        if (user == null) {
            // Perform dummy password check to prevent timing attacks
            passwordEncoder.matches(request.getPassword(), "$2a$10$dummyhashtopreventtimingattacks000000000000000000");
            rateLimitService.recordAttempt(ipAddress, request.getUsername());
            auditService.logEvent(null, "LOGIN", "Unknown user: " + request.getUsername(), ipAddress, userAgent, false);
            throw new AuthenticationException("Invalid credentials");
        }

        checkAccountLockout(user);

        if (!passwordEncoder.matches(request.getPassword(), user.getPasswordHash())) {
            handleFailedLogin(user, ipAddress, userAgent);
            throw new AuthenticationException("Invalid credentials");
        }

        // Reset failed attempts on successful password verification
        user.setFailedLoginAttempts(0);
        userRepository.save(user);

        if (user.isMfaEnabled()) {
            auditService.logEvent(user, "LOGIN_PASSWORD_OK", "MFA required", ipAddress, userAgent, true);
            return new ApiResponse(true, "MFA verification required", "MFA_REQUIRED");
        }

        auditService.logEvent(user, "LOGIN", "Successful login", ipAddress, userAgent, true);
        return new ApiResponse(true, "Login successful");
    }

    @Transactional
    public ApiResponse verifyMfa(MfaVerificationRequest request, String ipAddress, String userAgent) {
        rateLimitService.checkRateLimit(ipAddress, request.getUsername());

        User user = userRepository.findByUsername(request.getUsername())
                .orElseThrow(() -> new AuthenticationException("Invalid credentials"));

        checkAccountLockout(user);

        if (!user.isMfaEnabled() || user.getMfaSecret() == null) {
            throw new MfaException("MFA is not enabled for this account");
        }

        if (totpService.verifyCode(user.getMfaSecret(), request.getTotpCode())) {
            user.setFailedLoginAttempts(0);
            userRepository.save(user);
            auditService.logEvent(user, "MFA_VERIFY", "TOTP verification successful", ipAddress, userAgent, true);
            return new ApiResponse(true, "MFA verification successful");
        }

        handleFailedLogin(user, ipAddress, userAgent);
        auditService.logEvent(user, "MFA_VERIFY", "Invalid TOTP code", ipAddress, userAgent, false);
        throw new AuthenticationException("Invalid MFA code");
    }

    @Transactional
    public ApiResponse verifyBackupCode(BackupCodeRequest request, String ipAddress, String userAgent) {
        rateLimitService.checkRateLimit(ipAddress, request.getUsername());

        User user = userRepository.findByUsername(request.getUsername())
                .orElseThrow(() -> new AuthenticationException("Invalid credentials"));

        checkAccountLockout(user);

        if (!user.isMfaEnabled()) {
            throw new MfaException("MFA is not enabled for this account");
        }

        if (backupCodeService.validateAndConsumeBackupCode(user, request.getBackupCode(), ipAddress)) {
            user.setFailedLoginAttempts(0);
            userRepository.save(user);

            long remaining = backupCodeService.getRemainingCodesCount(user);
            auditService.logEvent(user, "BACKUP_CODE_USED",
                    "Backup code consumed. Remaining: " + remaining, ipAddress, userAgent, true);

            String message = "Backup code verified successfully.";
            if (remaining <= 2) {
                message += " WARNING: Only " + remaining + " backup codes remaining. Please generate new codes.";
            }

            return new ApiResponse(true, message, new BackupCodeStatusResponse(remaining, 10));
        }

        handleFailedLogin(user, ipAddress, userAgent);
        auditService.logEvent(user, "BACKUP_CODE_USED", "Invalid backup code", ipAddress, userAgent, false);
        throw new AuthenticationException("Invalid backup code");
    }

    @Transactional
    public MfaSetupResponse enableMfa(String username, String ipAddress, String userAgent) {
        User user = userRepository.findByUsername(username)
                .orElseThrow(() -> new AuthenticationException("User not found"));

        if (user.isMfaEnabled()) {
            throw new MfaException("MFA is already enabled");
        }

        String secret = totpService.generateSecret();
        String qrCodeUri = totpService.generateQrCodeUri(secret, username, ISSUER);

        user.setMfaSecret(secret);
        user.setMfaEnabled(true);
        userRepository.save(user);

        // Generate backup codes
        List<String> backupCodes = backupCodeService.generateBackupCodes(user);

        auditService.logEvent(user, "MFA_ENABLED", "MFA enabled with backup codes generated", ipAddress, userAgent, true);
        logger.info("MFA enabled for user: {}", username);

        return new MfaSetupResponse(
                secret,
                qrCodeUri,
                backupCodes,
                "MFA enabled successfully. Save your backup codes securely. They will not be shown again."
        );
    }

    @Transactional
    public ApiResponse disableMfa(String username, String password, String ipAddress, String userAgent) {
        User user = userRepository.findByUsername(username)
                .orElseThrow(() -> new AuthenticationException("User not found"));

        if (!passwordEncoder.matches(password, user.getPasswordHash())) {
            auditService.logEvent(user, "MFA_DISABLE_ATTEMPT", "Invalid password", ipAddress, userAgent, false);
            throw new AuthenticationException("Invalid password");
        }

        user.setMfaEnabled(false);
        user.setMfaSecret(null);
        userRepository.save(user);

        backupCodeService.revokeAllBackupCodes(user);

        auditService.logEvent(user, "MFA_DISABLED", "MFA disabled and backup codes revoked", ipAddress, userAgent, true);
        logger.info("MFA disabled for user: {}", username);

        return new ApiResponse(true, "MFA has been disabled");
    }

    @Transactional
    public MfaSetupResponse regenerateBackupCodes(String username, String password, String ipAddress, String userAgent) {
        User user = userRepository.findByUsername(username)
                .orElseThrow(() -> new AuthenticationException("User not found"));

        if (!user.isMfaEnabled()) {
            throw new MfaException("MFA is not enabled");
        }

        if (!passwordEncoder.matches(password, user.getPasswordHash())) {
            auditService.logEvent(user, "BACKUP_CODE_REGEN_ATTEMPT", "Invalid password", ipAddress, userAgent, false);
            throw new AuthenticationException("Invalid password");
        }

        List<String> newCodes = backupCodeService.generateBackupCodes(user);

        auditService.logEvent(user, "BACKUP_CODES_REGENERATED",
                "New backup codes generated, old codes revoked", ipAddress, userAgent, true);
        logger.info("Backup codes regenerated for user: {}", username);

        return new MfaSetupResponse(
                null,
                null,
                newCodes,
                "New backup codes generated. Previous codes have been revoked. Save these codes securely."
        );
    }

    public BackupCodeStatusResponse getBackupCodeStatus(String username) {
        User user = userRepository.findByUsername(username)
                .orElseThrow(() -> new AuthenticationException("User not found"));

        long remaining = backupCodeService.getRemainingCodesCount(user);
        return new BackupCodeStatusResponse(remaining, 10);
    }

    private void checkAccountLockout(User user) {
        if (user.isAccountLocked()) {
            if (user.getLockoutExpiry() != null && Instant.now().isAfter(user.getLockoutExpiry())) {
                // Lockout has expired, unlock the account
                user.setAccountLocked(false);
                user.setFailedLoginAttempts(0);
                user.setLockoutExpiry(null);
                userRepository.save(user);
            } else {
                throw new AccountLockedException("Account is locked until " + user.getLockoutExpiry());
            }
        }
    }

    private void handleFailedLogin(User user, String ipAddress, String userAgent) {
        int attempts = user.getFailedLoginAttempts() + 1;
        user.setFailedLoginAttempts(attempts);

        if (attempts >= MAX_FAILED_ATTEMPTS) {
            user.setAccountLocked(true);
            user.setLockoutExpiry(Instant.now().plus(LOCKOUT_DURATION_MINUTES, ChronoUnit.MINUTES));
            logger.warn("Account locked for user: {} after {} failed attempts", user.getUsername(), attempts);
            auditService.logEvent(user, "ACCOUNT_LOCKED",
                    "Account locked after " + attempts + " failed attempts", ipAddress, userAgent, false);
        }

        userRepository.save(user);
        rateLimitService.recordAttempt(ipAddress, user.getUsername());
    }
}

// ==================== Controller: AuthController ====================

package com.enterprise.auth.controller;

import com.enterprise.auth.dto.*;
import com.enterprise.auth.service.AuthenticationService;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.validation.Valid;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/auth")
public class AuthController {

    private final AuthenticationService authenticationService;

    public AuthController(AuthenticationService authenticationService) {
        this.authenticationService = authenticationService;
    }

    @PostMapping("/register")
    public ResponseEntity<ApiResponse> register(@Valid @RequestBody RegisterRequest request) {
        ApiResponse response = authenticationService.register(request);
        return response.isSuccess() ? ResponseEntity.ok(response) : ResponseEntity.badRequest().body(response);
    }

    @PostMapping("/login")
    public ResponseEntity<ApiResponse> login(@Valid @RequestBody LoginRequest request, HttpServletRequest httpRequest) {
        String ipAddress = getClientIp(httpRequest);
        String userAgent = httpRequest.getHeader("User-Agent");
        ApiResponse response = authenticationService.login(request, ipAddress, userAgent);
        return ResponseEntity.ok(response);
    }

    @PostMapping("/mfa/verify")
    public ResponseEntity<ApiResponse> verifyMfa(@Valid @RequestBody MfaVerificationRequest request,
                                                  HttpServletRequest httpRequest) {
        String ipAddress = getClientIp(httpRequest);
        String userAgent = httpRequest.getHeader("User-Agent");
        ApiResponse response = authenticationService.verifyMfa(request, ipAddress, userAgent);
        return ResponseEntity.ok(response);
    }

    @PostMapping("/mfa/backup-code/verify")
    public ResponseEntity<ApiResponse> verifyBackupCode(@Valid @RequestBody BackupCodeRequest request,
                                                         HttpServletRequest httpRequest) {
        String ipAddress = getClientIp(httpRequest);
        String userAgent = httpRequest.getHeader("User-Agent");
        ApiResponse response = authenticationService.verifyBackupCode(request, ipAddress, userAgent);
        return ResponseEntity.ok(response);
    }

    @PostMapping("/mfa/enable/{username}")
    public ResponseEntity<MfaSetupResponse> enableMfa(@PathVariable String username,
                                                       HttpServletRequest httpRequest) {
        String ipAddress = getClientIp(httpRequest);
        String userAgent = httpRequest.getHeader("User-Agent");
        MfaSetupResponse response = authenticationService.enableMfa(username, ipAddress, userAgent);
        return ResponseEntity.ok(response);
    }

    @PostMapping("/mfa/disable/{username}")
    public ResponseEntity<ApiResponse> disableMfa(@PathVariable String username,
                                                   @RequestParam String password,
                                                   HttpServletRequest httpRequest) {
        String ipAddress = getClientIp(httpRequest);
        String userAgent = httpRequest.getHeader("User-Agent");
        ApiResponse response = authenticationService.disableMfa(username, password, ipAddress, userAgent);
        return ResponseEntity.ok(response);
    }

    @PostMapping("/mfa/backup-codes/regenerate/{username}")
    public ResponseEntity<MfaSetupResponse> regenerateBackupCodes(@PathVariable String username,
                                                                    @RequestParam String password,
                                                                    HttpServletRequest httpRequest) {
        String ipAddress = getClientIp(httpRequest);
        String userAgent = httpRequest.getHeader("User-Agent");
        MfaSetupResponse response = authenticationService.regenerateBackupCodes(username, password, ipAddress, userAgent);
        return ResponseEntity.ok(response);
    }

    @GetMapping("/mfa/backup-codes/status/{username}")
    public ResponseEntity<BackupCodeStatusResponse> getBackupCodeStatus(@PathVariable String username) {
        BackupCodeStatusResponse response = authenticationService.getBackupCodeStatus(username);
        return ResponseEntity.ok(response);
    }

    private String getClientIp(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            // Take the first IP in the chain (original client)
            String ip = xForwardedFor.split(",")[0].trim();
            // Validate IP format to prevent header injection
            if (ip.matches("^[0-9a-fA-F.:]+$") && ip.length() <= 45) {
                return ip;
            }
        }
        return request.getRemoteAddr();
    }
}

// ==================== Security Configuration ====================

package com.enterprise.auth.config;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.config.http.SessionCreationPolicy;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.security.web.SecurityFilterChain;

@Configuration
@EnableWebSecurity
public class SecurityConfig {

    @Bean
    public PasswordEncoder passwordEncoder() {
        // BCrypt with strength 12 for both passwords and backup codes
        return new BCryptPasswordEncoder(12);
    }

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        http
            .csrf(csrf -> csrf.disable()) // Disable for API - use token-based auth in production
            .sessionManagement(session -> session.sessionCreationPolicy(SessionCreationPolicy.STATELESS))
            .authorizeHttpRequests(auth -> auth
                .requestMatchers("/api/auth/register", "/api/auth/login",
                        "/api/auth/mfa/verify", "/api/auth/mfa/backup-code/verify").permitAll()
                .requestMatchers("/h2-console/**").permitAll()
                .anyRequest().authenticated()
            )
            .headers(headers -> headers.frameOptions(frame -> frame.sameOrigin())); // For H2 console

        return http.build();
    }
}

// ==================== Scheduled Tasks ====================

package com.enterprise.auth.config;

import com.enterprise.auth.service.BackupCodeService;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.context.annotation.Configuration;
import org.springframework.scheduling.annotation.EnableAsync;
import org.springframework.scheduling.annotation.EnableScheduling;
import org.springframework.scheduling.annotation.Scheduled;

@Configuration
@EnableScheduling
@EnableAsync
public class ScheduledTasksConfig {

    private static final Logger logger = LoggerFactory.getLogger(ScheduledTasksConfig.class);

    private final BackupCodeService backupCodeService;

    public ScheduledTasksConfig(BackupCodeService backupCodeService) {
        this.backupCodeService = backupCodeService;
    }

    // Run daily at 2 AM to clean up expired backup codes
    @Scheduled(cron = "0 0 2 * * ?")
    public void cleanupExpiredBackupCodes() {
        logger.info("Starting expired backup code cleanup");
        int deleted = backupCodeService.cleanupExpiredCodes();
        logger.info("Expired backup code cleanup completed. Deleted: {}", deleted);
    }
}

